  const [globalDiscount, setGlobalDiscount] = useState(25);

  // Dashboard açıldığında performans kontrolü yap
  useEffect(() => {
    if (currentRole === 'MANAGER') {
       checkServicePerformance();
    }
  }, [currentRole]);

  // GELİR GRAFİĞİ VERİSİ
  const chartData = useMemo(() => {
    const data: Record<string, { name: string; revenue: number; sortKey: string }> = {};

    if (transactions.length === 0) {
        // Veri yoksa son 6 ayı boş göster
        const today = new Date();
        for(let i=5; i>=0; i--) {
            const d = new Date(today.getFullYear(), today.getMonth() - i, 1);
            const key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
            const name = d.toLocaleString('tr-TR', { month: 'short' });
            data[key] = { name, revenue: 0, sortKey: key };
        }
    } else {
        transactions.forEach(t => {
            const date = new Date(t.timestamp);
            const monthNames = ["Oca", "Şub", "Mar", "Nis", "May", "Haz", "Tem", "Ağu", "Eyl", "Eki", "Kas", "Ara"];
            const monthIndex = date.getMonth();
            const year = date.getFullYear();
            const sortKey = `${year}-${String(monthIndex + 1).padStart(2, '0')}`;
            const name = `${monthNames[monthIndex]}`;

            if (!data[sortKey]) {
                data[sortKey] = { name, revenue: 0, sortKey };
            }
            data[sortKey].revenue += t.grossRevenue;
        });
    }

    return Object.values(data).sort((a, b) => a.sortKey.localeCompare(b.sortKey));
  }, [transactions]);

  // PERSONEL PERFORMANS GRAFİĞİ VERİSİ
  const topStaff = useMemo(() => {
     return [...staff].sort((a, b) => b.performanceScore - a.performanceScore).slice(0, 5);
  }, [staff]);

  const staffPerfData = useMemo(() => {
      const last6Months = [];
      const today = new Date();
      for (let i = 5; i >= 0; i--) {
          const d = new Date(today.getFullYear(), today.getMonth() - i, 1);
          last6Months.push({
              monthKey: `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`,
              name: d.toLocaleString('tr-TR', { month: 'short' })
          });
      }

      return last6Months.map(m => {
          const entry: any = { name: m.name };
          topStaff.forEach(s => {
              const monthlyTx = transactions.filter(t => {
                  const tDate = new Date(t.timestamp);
                  const tKey = `${tDate.getFullYear()}-${String(tDate.getMonth() + 1).padStart(2, '0')}`;
                  return tKey === m.monthKey && t.staffId === s.id && t.rating;
              });

              if (monthlyTx.length > 0) {
                  const avgRating = monthlyTx.reduce((sum, t) => sum + (t.rating || 0), 0) / monthlyTx.length;
                  entry[s.name] = Math.round(avgRating * 20); // 5 üzerinden puanı 100'e çevir
              } else {
                  // Veri yoksa mevcut performans skorunu baz al
                  const variation = Math.floor(Math.random() * 5) - 2;
                  entry[s.name] = Math.min(100, Math.max(0, s.performanceScore + variation));
              }
          });
          return entry;
      });
  }, [transactions, topStaff, staff]);

