import { initializeApp } from "firebase/app";
import { getFirestore, enableIndexedDbPersistence } from "firebase/firestore";

// ÖNEMLİ: Firebase Console'dan (https://console.firebase.google.com) 
// kendi projenizi oluşturup aşağıdaki bilgileri oradan alarak doldurunuz.

const firebaseConfig = {
  // Lütfen kendi API anahtarlarınızı buraya girin
  apiKey: "AIzaSyDOC_SİZİN_API_KEYİNİZ_BURAYA",
  authDomain: "sizin-projeniz.firebaseapp.com",
  projectId: "sizin-proje-id",
  storageBucket: "sizin-projeniz.appspot.com",
  messagingSenderId: "123456789",
  appId: "1:123456789:web:abcdef123456"
};

// Check if we are using placeholder config
export const isDemoMode = firebaseConfig.apiKey.includes("SİZİN_API_KEYİNİZ_BURAYA");

let app;
let db: any = null;

if (!isDemoMode) {
  try {
    app = initializeApp(firebaseConfig);
    db = getFirestore(app);

    // OFFLINE PERSISTENCE (İnternet yokken çalışma özelliği)
    enableIndexedDbPersistence(db).catch((err) => {
        if (err.code == 'failed-precondition') {
            console.warn('Persistence failed: Multiple tabs open');
        } else if (err.code == 'unimplemented') {
            console.warn('Persistence is not available in this browser');
        }
    });
  } catch (error) {
    console.error("Firebase initialization error:", error);
    // @ts-ignore
    isDemoMode = true; // Fallback to demo mode on error
  }
} else {
  console.log("Starting in DEMO MODE (Local Storage)");
}

