import React, { useState, useMemo } from 'react';
import { useSalon } from '../store/SalonContext';
import { Calendar, Clock, MessageSquare, Plus, Trash2, X, User, Activity, MessageCircle, ChevronLeft, ChevronRight, CheckCircle2, Bell, Send } from 'lucide-react';

export const Appointments: React.FC = () => {
  const { appointments, customers, services, staff, addAppointment, updateAppointmentStatus, deleteData, currentRole } = useSalon();
  const [showForm, setShowForm] = useState(false);
  const [selectedDate, setSelectedDate] = useState(new Date().toISOString().split('T')[0]);
  const [newApp, setNewApp] = useState({ customerId: '', serviceId: '', staffId: '', date: new Date().toISOString().split('T')[0], time: '' });

  // Saat Dilimleri (09:00 - 20:00)
  const timeSlots = Array.from({ length: 12 }, (_, i) => {
    const hour = i + 9;
    return `${hour < 10 ? '0' + hour : hour}:00`;
  });

  const handleAdd = () => {
    if(!newApp.customerId || !newApp.date || !newApp.time) return;
    addAppointment({
      id: Math.random().toString(36).substr(2, 9),
      ...newApp,
      status: 'PENDING',
      reminderSent: false
    });
    setShowForm(false);
  };

  const handleNotifyWhatsApp = (customer: any, app: any) => {
    const serviceName = services.find(s => s.id === app.serviceId)?.name || 'Hizmet';
    const message = `Merhaba Sayın ${customer.fullName}, L'YSF Life Center'dan randevu hatırlatması: ${app.date} tarihinde saat ${app.time}'da ${serviceName} randevunuz bulunmaktadır. Sizi bekliyoruz! ✨`;
    const phone = customer.phone.replace(/\D/g, '');
    const url = `https://wa.me/${phone}?text=${encodeURIComponent(message)}`;
    window.open(url, '_blank');
  };

  const handleTodayReminders = () => {
      const todayStr = new Date().toISOString().split('T')[0];
      const todaysAppointments = appointments.filter(a => a.date === todayStr && a.status === 'PENDING');

      if (todaysAppointments.length === 0) {
          alert(`Bugün (${todayStr}) için hatırlatılacak bekleyen randevu yok.`);
          return;
      }

      if (confirm(`Bugün tarihli ${todaysAppointments.length} adet randevu için WhatsApp hatırlatması gönderilsin mi?`)) {
          alert(`✅ İŞLEM BAŞLATILDI: ${todaysAppointments.length} kişiye 'Bugün Randevunuz Var' mesajı gönderim kuyruğuna alındı.`);
      }
  };

  const handleAutoReminders = () => {
      // 1 gün sonrasını hesapla
      const tomorrow = new Date();
      tomorrow.setDate(tomorrow.getDate() + 1);
      const dateStr = tomorrow.toISOString().split('T')[0];

      // Yarınki randevuları bul
      const tomorrowsAppointments = appointments.filter(a => a.date === dateStr);

      if (tomorrowsAppointments.length === 0) {
          alert(`Yarın (${dateStr}) için planlanmış randevu bulunamadı.`);
          return;
      }

      // Burada gerçek bir SMS servisi olmadığı için simüle ediyoruz
      // Normalde backend'e bir istek atılırdı.
      alert(`✅ BAŞARILI: Yarın için toplam ${tomorrowsAppointments.length} müşteriye ve ilgili personele otomatik hatırlatma SMS/E-posta kuyruğa eklendi.`);
  };

  const dailyAppointments = useMemo(() => {
    return appointments.filter(a => a.date === selectedDate);
  }, [appointments, selectedDate]);

  const getAppointmentsForSlot = (time: string) => {
    return dailyAppointments.filter(a => a.time >= time && a.time < `${parseInt(time) + 1}:00`).sort((a,b) => a.time.localeCompare(b.time));
  };

  const changeDate = (days: number) => {
    const d = new Date(selectedDate);
    d.setDate(d.getDate() + days);
    setSelectedDate(d.toISOString().split('T')[0]);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-700">
      {/* Header & Date Controls */}
      <div className="bg-white rounded-[3rem] p-8 shadow-xl border border-slate-100 flex flex-col md:flex-row justify-between items-center gap-6">
        <div className="flex items-center gap-6">
           <div className="bg-rose-50 p-4 rounded-2xl text-rose-500"><Calendar size={32} /></div>
           <div>
              <h2 className="text-3xl font-black text-slate-900 tracking-tight italic">Randevu Ajandası</h2>
              <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">GÜNLÜK PLANLAMA</p>
           </div>
        </div>

        <div className="flex items-center gap-4 bg-slate-50 p-2 rounded-full border border-slate-100">
           <button onClick={() => changeDate(-1)} className="p-3 bg-white rounded-full shadow-sm hover:bg-slate-900 hover:text-white transition-all"><ChevronLeft size={20}/></button>
           <div className="px-6 text-center min-w-[150px]">
              <span className="block text-sm font-black text-slate-900 uppercase tracking-widest">
                {new Date(selectedDate).toLocaleDateString('tr-TR', { day: 'numeric', month: 'long', weekday: 'long' })}
              </span>
           </div>
           <button onClick={() => changeDate(1)} className="p-3 bg-white rounded-full shadow-sm hover:bg-slate-900 hover:text-white transition-all"><ChevronRight size={20}/></button>
        </div>

        <div className="flex gap-2">
            <button 
                onClick={handleTodayReminders}
                className="bg-emerald-500 text-white px-6 py-4 rounded-[2rem] font-black uppercase text-xs tracking-widest shadow-xl hover:bg-emerald-600 transition-all flex items-center gap-2"
                title="Bugünkü randevulara hatırlatma gönder"
            >
                <Send size={18} /> Bugün
            </button>
            <button 
                onClick={handleAutoReminders}
                className="bg-indigo-500 text-white px-6 py-4 rounded-[2rem] font-black uppercase text-xs tracking-widest shadow-xl hover:bg-indigo-600 transition-all flex items-center gap-2"
                title="Yarınki tüm randevulara otomatik hatırlatma gönder"
            >
                <Bell size={18} /> Yarın
            </button>
            <button 
              onClick={() => setShowForm(true)}
              className="bg-slate-900 text-white px-8 py-4 rounded-[2rem] font-black uppercase text-xs tracking-widest shadow-xl hover:bg-black transition-all flex items-center gap-3"
            >
              <Plus size={18} /> Yeni Randevu
            </button>
        </div>
      </div>

      {/* Timeline View */}
      <div className="bg-white rounded-[3rem] shadow-xl border border-slate-100 overflow-hidden relative min-h-[800px]">
         <div className="absolute left-24 top-0 bottom-0 w-px bg-slate-100 z-0"></div>

         <div className="divide-y divide-slate-50 relative z-10">
            {timeSlots.map(time => {
              const slotApps = getAppointmentsForSlot(time);
              return (
                <div key={time} className="flex min-h-[120px] group hover:bg-slate-50/30 transition-colors">
                   {/* Time Column */}
                   <div className="w-24 flex-shrink-0 p-6 text-right border-r border-slate-100 bg-white sticky left-0 z-20">
                      <span className="text-sm font-black text-slate-400 group-hover:text-rose-500 transition-colors">{time}</span>
                   </div>

                   {/* Appointments Area */}
                   <div className="flex-1 p-4 flex flex-wrap gap-4 items-start content-start">
                      {slotApps.length === 0 && (
                        <div className="w-full h-full flex items-center opacity-0 group-hover:opacity-100 transition-opacity px-4">
                           <button onClick={() => { setNewApp({...newApp, date: selectedDate, time}); setShowForm(true); }} className="text-xs font-bold text-slate-300 hover:text-indigo-500 flex items-center gap-2 border border-dashed border-slate-200 px-4 py-2 rounded-xl">
                              <Plus size={14}/> Bu Saate Ekle
                           </button>
                        </div>
                      )}

                      {slotApps.map(app => {
                        const customer = customers.find(c => c.id === app.customerId);
                        const service = services.find(s => s.id === app.serviceId);
                        const staffMember = staff.find(s => s.id === app.staffId);

                        return (
                          <div key={app.id} className={`relative p-5 rounded-[2rem] border shadow-sm min-w-[280px] hover:shadow-lg transition-all flex flex-col gap-2 ${app.status === 'COMPLETED' ? 'bg-emerald-50 border-emerald-100 opacity-70' : 'bg-white border-slate-200'}`}>
                             <div className="flex justify-between items-start">
                                <div className="flex items-center gap-2">
                                   <Clock size={14} className={app.status === 'COMPLETED' ? "text-emerald-500" : "text-rose-500"} />
                                   <span className="text-sm font-black text-slate-900">{app.time}</span>
                                </div>
                                {app.status === 'COMPLETED' && <CheckCircle2 size={16} className="text-emerald-500" />}
                             </div>

                             <div>
                                <h4 className="font-black text-slate-900 italic truncate">{customer?.fullName}</h4>
                                <p className="text-[10px] font-bold text-indigo-500 uppercase tracking-widest truncate">{service?.name}</p>
                             </div>

                             <div className="flex items-center gap-2 mt-2 pt-2 border-t border-slate-100/50">
                                <div className="w-6 h-6 rounded-full bg-slate-100 flex items-center justify-center text-[10px] font-black text-slate-500">
                                   {staffMember?.name.charAt(0)}
                                </div>
                                <span className="text-[10px] font-bold text-slate-400 truncate max-w-[100px]">{staffMember?.name}</span>
                             </div>

                             {/* Actions Overlay */}
                             <div className="absolute top-2 right-2 flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                <button onClick={() => handleNotifyWhatsApp(customer, app)} className="p-2 bg-emerald-50 text-emerald-600 rounded-xl hover:bg-emerald-500 hover:text-white" title="WhatsApp"><MessageCircle size={14}/></button>
                                {app.status === 'PENDING' && (
                                   <button onClick={() => updateAppointmentStatus(app.id, 'COMPLETED')} className="p-2 bg-indigo-50 text-indigo-600 rounded-xl hover:bg-indigo-500 hover:text-white" title="Tamamla"><CheckCircle2 size={14}/></button>
                                )}
                                {currentRole === 'MANAGER' && (
                                   <button onClick={() => deleteData(app.id, 'APPOINTMENT')} className="p-2 bg-rose-50 text-rose-600 rounded-xl hover:bg-rose-500 hover:text-white" title="Sil"><Trash2 size={14}/></button>
                                )}
                             </div>
                          </div>
                        );
                      })}
                   </div>
                </div>
              );
            })}
         </div>
      </div>

      {/* Randevu Ekleme Modalı */}
      {showForm && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center bg-slate-900/60 backdrop-blur-md p-4">
          <div className="bg-white w-full max-w-xl rounded-[3rem] p-10 shadow-3xl animate-in zoom-in-95">
            <div className="flex justify-between items-center mb-10">
              <h3 className="text-2xl font-black italic">Randevu Oluştur</h3>
              <button onClick={() => setShowForm(false)} className="p-2 hover:bg-slate-100 rounded-full"><X /></button>
            </div>
            <div className="space-y-6">
              <div>
                <label className="text-[10px] font-black uppercase text-slate-400 mb-2 block">Müşteri Seç</label>
                <select value={newApp.customerId} onChange={e => setNewApp({...newApp, customerId: e.target.value})} className="w-full p-4 bg-slate-50 rounded-2xl border border-slate-200 font-bold outline-none focus:border-slate-900 transition-all">
                  <option value="">Seçiniz...</option>
                  {customers.map(c => <option key={c.id} value={c.id}>{c.fullName}</option>)}
                </select>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="text-[10px] font-black uppercase text-slate-400 mb-2 block">Hizmet</label>
                  <select value={newApp.serviceId} onChange={e => setNewApp({...newApp, serviceId: e.target.value})} className="w-full p-4 bg-slate-50 rounded-2xl border border-slate-200 font-bold outline-none focus:border-slate-900 transition-all">
                    <option value="">Seçiniz...</option>
                    {services.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                  </select>
                </div>
                <div>
                  <label className="text-[10px] font-black uppercase text-slate-400 mb-2 block">Uzman</label>
                  <select value={newApp.staffId} onChange={e => setNewApp({...newApp, staffId: e.target.value})} className="w-full p-4 bg-slate-50 rounded-2xl border border-slate-200 font-bold outline-none focus:border-slate-900 transition-all">
                    <option value="">Seçiniz...</option>
                    {staff.map(st => <option key={st.id} value={st.id}>{st.name}</option>)}
                  </select>
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="text-[10px] font-black uppercase text-slate-400 mb-2 block">Tarih</label>
                  <input type="date" value={newApp.date} onChange={e => setNewApp({...newApp, date: e.target.value})} className="w-full p-4 bg-slate-50 rounded-2xl border border-slate-200 font-bold outline-none focus:border-slate-900 transition-all" />
                </div>
                <div>
                  <label className="text-[10px] font-black uppercase text-slate-400 mb-2 block">Saat</label>
                  <input type="time" value={newApp.time} onChange={e => setNewApp({...newApp, time: e.target.value})} className="w-full p-4 bg-slate-50 rounded-2xl border border-slate-200 font-bold outline-none focus:border-slate-900 transition-all" />
                </div>
              </div>
              <button onClick={handleAdd} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black text-lg hover:bg-black transition-all shadow-xl">Randevuyu Kaydet</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { useSalon } from '../store/SalonContext';
import { UserRole, Customer, DietDay, ChatMessage } from '../types';
import { 
  Apple, Search, MessageCircle, Edit, Save, 
  Send, Image as ImageIcon, Phone, Eye, EyeOff, 
  UserCheck, ShieldCheck, ChevronRight, Lock, Unlock, FileText, Activity, Scale,
  Video, Mic, MicOff, VideoOff, PhoneOff, Clock, Calendar, X, Settings, TrendingUp,
  Trash2, Copy, RefreshCw, Droplets, Plus, Minus
} from 'lucide-react';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

interface DietitianCockpitProps {
  setTab: (tab: string) => void;
}

export const DietitianCockpit: React.FC<DietitianCockpitProps> = ({ setTab }) => {
  const { customers, currentRole, updateDietPlan, sendDietMessage } = useSalon();

  // State
  const [selectedCustomerId, setSelectedCustomerId] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState<'PLAN' | 'CHAT' | 'ANALYSIS'>('PLAN');
  const [searchTerm, setSearchTerm] = useState('');

  // Chat States
  const [chatInput, setChatInput] = useState('');
  const chatScrollRef = useRef<HTMLDivElement>(null);

  // Call & Schedule States
  const [showCallMenu, setShowCallMenu] = useState(false);
  const [scheduleTime, setScheduleTime] = useState('');
  const [activeCall, setActiveCall] = useState<{status: 'RINGING' | 'CONNECTED', type: 'VIDEO' | 'AUDIO'} | null>(null);

  // Diet Plan Editor State
  const [dietPlan, setDietPlan] = useState<DietDay[]>([]);

  const selectedCustomer = customers.find(c => c.id === selectedCustomerId);

  const isManager = currentRole === UserRole.MANAGER;
  const canAccess = [UserRole.MANAGER, UserRole.EXPERT, UserRole.RECEPTIONIST].includes(currentRole);

  useEffect(() => {
    if (selectedCustomer) {
      if (selectedCustomer.dietPlan && selectedCustomer.dietPlan.length > 0) {
        setDietPlan(selectedCustomer.dietPlan);
      } else {
        resetPlan();
      }
    }
  }, [selectedCustomer]);

  useEffect(() => {
    if (chatScrollRef.current) {
      chatScrollRef.current.scrollTop = chatScrollRef.current.scrollHeight;
    }
  }, [selectedCustomer?.dietChatHistory, activeTab]);

  const resetPlan = () => {
    const days = ['Pazartesi', 'Salı', 'Çarşamba', 'Perşembe', 'Cuma', 'Cumartesi', 'Pazar'];
    setDietPlan(days.map(d => ({
      dayName: d,
      meals: { 
        breakfast: { title: 'Kahvaltı', content: '' }, 
        lunch: { title: 'Öğle', content: '' }, 
        dinner: { title: 'Akşam', content: '' }, 
        snacks: [] 
      },
      waterTarget: 2.5,
      notes: ''
    })));
  };

  if (!canAccess) {
    return <div className="p-20 text-center text-slate-400 font-black">Erişim Yetkiniz Yok.</div>;
  }

  const handleSavePlan = () => {
    if (selectedCustomerId) {
      updateDietPlan(selectedCustomerId, dietPlan);
      alert("Diyet programı müşteriye iletildi!");
    }
  };

  const handleClearPlan = () => {
      if(confirm("Tüm listeyi temizleyip sıfırdan oluşturmak istiyor musunuz?")) {
          resetPlan();
      }
  };

  const handleCopyPreviousDay = (currentIndex: number) => {
      if (currentIndex === 0) return;
      const prevDay = dietPlan[currentIndex - 1];
      const newPlan = [...dietPlan];

      // Deep copy meals to avoid reference issues
      newPlan[currentIndex] = {
          ...newPlan[currentIndex],
          meals: JSON.parse(JSON.stringify(prevDay.meals)),
          waterTarget: prevDay.waterTarget,
          notes: prevDay.notes
      };
      setDietPlan(newPlan);
  };

  const handleSendMessage = () => {
    if (!selectedCustomerId || !chatInput.trim()) return;
    sendDietMessage(selectedCustomerId, {
      sender: isManager ? 'MANAGER' : 'DIETITIAN',
      content: chatInput,
      type: 'TEXT'
    });
    setChatInput('');
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0] && selectedCustomerId) {
      const file = e.target.files[0];
      const reader = new FileReader();
      reader.onloadend = () => {
        sendDietMessage(selectedCustomerId, {
          sender: isManager ? 'MANAGER' : 'DIETITIAN',
          content: reader.result as string,
          type: 'IMAGE'
        });
      };
      reader.readAsDataURL(file);
      e.target.value = ''; // Reset input to allow re-uploading same file
    }
  };

  // --- CALL LOGIC ---
  const startCall = (type: 'VIDEO' | 'AUDIO') => {
      setShowCallMenu(false);
      setActiveCall({ status: 'RINGING', type });
      // Simulate connection after 3 seconds
      setTimeout(() => {
          setActiveCall(prev => prev ? { ...prev, status: 'CONNECTED' } : null);
      }, 3000);

      // Send system message about the call
      if (selectedCustomerId) {
          sendDietMessage(selectedCustomerId, {
              sender: isManager ? 'MANAGER' : 'DIETITIAN',
              content: `${type === 'VIDEO' ? 'Görüntülü' : 'Sesli'} görüşme başlatıldı.`,
              type: 'CALL_REQUEST'
          });
      }
  };

  const endCall = () => {
      setActiveCall(null);
      if (selectedCustomerId) {
        sendDietMessage(selectedCustomerId, {
            sender: isManager ? 'MANAGER' : 'DIETITIAN',
            content: `Görüşme sonlandı. (${new Date().toLocaleTimeString()})`,
            type: 'TEXT'
        });
      }
  };

  const sendAppointmentRequest = () => {
      if (!selectedCustomerId || !scheduleTime) return;
      sendDietMessage(selectedCustomerId, {
          sender: isManager ? 'MANAGER' : 'DIETITIAN',
          content: `📅 Online Görüşme Randevusu\n⏰ Saat: ${scheduleTime}\n\nLütfen belirtilen saatte uygulama üzerinden çevrimiçi olunuz.`,
          type: 'TEXT'
      });
      setScheduleTime('');
      setShowCallMenu(false);
  };

  const filteredCustomers = customers.filter(c => 
    c.fullName.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="h-[calc(100vh-200px)] flex gap-6 animate-in fade-in duration-500 relative">

      {/* ACTIVE CALL OVERLAY */}
      {activeCall && selectedCustomer && (
          <div className="fixed inset-0 z-[999] bg-slate-900 flex flex-col items-center justify-center text-white animate-in zoom-in-95 duration-500">
              <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')] opacity-10"></div>
              {activeCall.type === 'VIDEO' && (
                  <div className="absolute inset-0 bg-gradient-to-b from-slate-800 to-black opacity-50">
                      {/* Fake Video Placeholder */}
                      <div className="w-full h-full flex items-center justify-center">
                          <UserCheck size={120} className="opacity-20"/>
                      </div>
                  </div>
              )}

              <div className="relative z-10 flex flex-col items-center gap-8">
                  <div className="w-32 h-32 rounded-full bg-slate-800 border-4 border-slate-700 flex items-center justify-center shadow-2xl overflow-hidden relative">
                      <span className="text-4xl font-black">{selectedCustomer.fullName.charAt(0)}</span>
                      {activeCall.status === 'RINGING' && <div className="absolute inset-0 border-4 border-emerald-500 rounded-full animate-ping"></div>}
                  </div>

                  <div className="text-center space-y-2">
                      <h2 className="text-4xl font-black tracking-tighter">{selectedCustomer.fullName}</h2>
                      <p className="text-emerald-400 font-bold uppercase tracking-widest animate-pulse">
                          {activeCall.status === 'RINGING' ? 'Aranıyor...' : '00:12 • Canlı Bağlantı'}
                      </p>
                  </div>

                  <div className="flex items-center gap-6 mt-10">
                      <button className="p-6 rounded-full bg-white/10 hover:bg-white/20 transition-all backdrop-blur-md"><MicOff size={24}/></button>
                      {activeCall.type === 'VIDEO' && <button className="p-6 rounded-full bg-white/10 hover:bg-white/20 transition-all backdrop-blur-md"><VideoOff size={24}/></button>}
                      <button onClick={endCall} className="p-8 rounded-full bg-rose-500 hover:bg-rose-600 transition-all shadow-xl hover:scale-110 active:scale-95">
                          <PhoneOff size={32} fill="white" />
                      </button>
                  </div>
              </div>
          </div>
      )}

      {/* LEFT SIDEBAR: Patient List */}
      <div className="w-80 bg-white rounded-[2.5rem] border border-slate-100 shadow-xl flex flex-col overflow-hidden">
        <div className="p-6 bg-slate-50 border-b border-slate-100">
           <div className="flex justify-between items-center mb-4">
               <h3 className="text-xl font-black italic text-slate-900 flex items-center gap-2">
                 <Apple className="text-emerald-500" /> Danışanlar
               </h3>
               <button 
                  onClick={() => setTab('system-management')} 
                  className="px-3 py-2 bg-white border border-slate-200 rounded-lg text-slate-500 hover:text-indigo-600 hover:border-indigo-200 transition-all shadow-sm flex items-center gap-2 text-[10px] font-black uppercase tracking-widest"
               >
                  <Settings size={14} /> Rehber / Ayar
               </button>
           </div>
           <div className="relative">
             <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
             <input 
               value={searchTerm} 
               onChange={e => setSearchTerm(e.target.value)} 
               placeholder="İsim Ara..." 
               className="w-full pl-10 pr-4 py-3 rounded-xl bg-white border border-slate-200 text-sm font-bold outline-none focus:border-emerald-500 transition-all"
             />
           </div>
        </div>
        <div className="flex-1 overflow-y-auto p-4 space-y-2 no-scrollbar">
           {filteredCustomers.map(c => (
             <button 
               key={c.id} 
               onClick={() => setSelectedCustomerId(c.id)}
               className={`w-full p-4 rounded-2xl flex items-center justify-between transition-all group ${selectedCustomerId === c.id ? 'bg-emerald-500 text-white shadow-lg' : 'bg-white hover:bg-slate-50 border border-transparent hover:border-slate-100'}`}
             >
               <div className="text-left">
                 <p className="font-black text-sm">{c.fullName}</p>
                 <p className={`text-[10px] font-bold uppercase tracking-widest ${selectedCustomerId === c.id ? 'text-emerald-100' : 'text-slate-400'}`}>{c.tier}</p>
               </div>
               {c.dietChatHistory && c.dietChatHistory.some(m => !m.isRead && m.sender === 'CUSTOMER') && (
                 <div className="w-3 h-3 bg-rose-500 rounded-full animate-pulse border-2 border-white"></div>
               )}
             </button>
           ))}
        </div>
      </div>

      {/* MAIN CONTENT AREA */}
      <div className="flex-1 bg-white rounded-[2.5rem] border border-slate-100 shadow-xl flex flex-col overflow-hidden relative">
        {!selectedCustomer ? (
          <div className="flex-1 flex flex-col items-center justify-center opacity-30">
             <Apple size={80} className="mb-4" />
             <p className="text-2xl font-black italic">Bir Danışan Seçin</p>
          </div>
        ) : (
          <>
            {/* Header */}
            <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50/50 backdrop-blur-md">
               <div className="flex items-center gap-4">
                  <div className="w-12 h-12 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center font-black text-lg">
                    {selectedCustomer.fullName.charAt(0)}
                  </div>
                  <div>
                    <h2 className="text-2xl font-black text-slate-900 italic">{selectedCustomer.fullName}</h2>
                    <p className="text-xs font-bold text-slate-50 flex items-center gap-2">
                       {selectedCustomer.phone} 
                       {isManager && <span className="px-2 py-0.5 bg-slate-200 rounded text-[9px]">MANAGER VIEW</span>}
                    </p>
                  </div>
               </div>

               <div className="flex bg-white p-1 rounded-xl shadow-sm border border-slate-100">
                  <button 
                    onClick={() => setActiveTab('PLAN')} 
                    className={`px-6 py-2 rounded-lg text-xs font-black uppercase tracking-widest transition-all flex items-center gap-2 ${activeTab === 'PLAN' ? 'bg-slate-900 text-white shadow-md' : 'text-slate-400 hover:bg-slate-50'}`}
                  >
                    <FileText size={14}/> Program
                  </button>
                  <button 
                    onClick={() => setActiveTab('ANALYSIS')} 
                    className={`px-6 py-2 rounded-lg text-xs font-black uppercase tracking-widest transition-all flex items-center gap-2 ${activeTab === 'ANALYSIS' ? 'bg-amber-500 text-white shadow-md' : 'text-slate-400 hover:bg-slate-50'}`}
                  >
                    <Scale size={14}/> Analiz
                  </button>
                  <button 
                    onClick={() => setActiveTab('CHAT')} 
                    className={`px-6 py-2 rounded-lg text-xs font-black uppercase tracking-widest transition-all flex items-center gap-2 ${activeTab === 'CHAT' ? 'bg-emerald-500 text-white shadow-md' : 'text-slate-400 hover:bg-slate-50'}`}
                  >
                    <MessageCircle size={14}/> İletişim
                  </button>
               </div>
            </div>

            {/* TAB CONTENT: PLAN EDITOR */}
            {activeTab === 'PLAN' && (
              <div className="flex-1 overflow-y-auto p-8 bg-slate-50">
                 <div className="max-w-6xl mx-auto space-y-8">
                    <div className="flex justify-between items-center bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm">
                       <h3 className="text-2xl font-black italic text-slate-700 flex items-center gap-3">
                           <Apple className="text-emerald-500"/> Haftalık Beslenme Programı
                       </h3>
                       <div className="flex gap-2">
                           <button onClick={handleClearPlan} className="px-6 py-4 bg-slate-100 text-slate-500 rounded-2xl font-black uppercase text-xs tracking-widest hover:bg-rose-50 hover:text-rose-500 transition-all flex items-center gap-2">
                              <Trash2 size={16} /> Listeyi Temizle
                           </button>
                           <button onClick={handleSavePlan} className="px-8 py-4 bg-emerald-500 text-white rounded-2xl font-black shadow-xl hover:bg-emerald-600 transition-all flex items-center gap-2 active:scale-95">
                              <Save size={18} /> KAYDET VE GÖNDER
                           </button>
                       </div>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6 pb-20">
                       {dietPlan.map((day, idx) => (
                         <div key={idx} className="bg-white p-6 rounded-[2.5rem] border border-slate-100 shadow-sm hover:shadow-md transition-all relative group">

                            {/* Copy Previous Day Button (Not for Monday) */}
                            {idx > 0 && (
                                <button 
                                    onClick={() => handleCopyPreviousDay(idx)}
                                    className="absolute top-4 right-16 p-2 bg-slate-50 text-slate-400 rounded-lg hover:bg-indigo-50 hover:text-indigo-600 transition-all"
                                    title="Önceki günü kopyala"
                                >
                                    <Copy size={14}/>
                                </button>
                            )}

                            <div className="flex justify-between items-center mb-6 pb-4 border-b border-slate-50">
                               <span className="font-black text-xl text-slate-800 italic">{day.dayName}</span>
                               <div className="flex items-center gap-2 bg-indigo-50 px-2 py-1 rounded-xl">
                                   <Droplets size={12} className="text-indigo-500"/>
                                   <input 
                                     type="number" 
                                     step="0.5"
                                     value={day.waterTarget} 
                                     onChange={(e) => {
                                        const newPlan = [...dietPlan];
                                        newPlan[idx].waterTarget = Number(e.target.value);
                                        setDietPlan(newPlan);
                                     }}
