                                     value={day.meals.lunch.content}
                                     onChange={(e) => {
                                        const newPlan = [...dietPlan];
                                        newPlan[idx].meals.lunch.content = e.target.value;
                                        setDietPlan(newPlan);
                                     }}
                                     className="w-full p-4 pt-8 bg-slate-50 border border-slate-100 rounded-2xl text-sm font-medium resize-none h-28 focus:border-emerald-300 outline-none transition-all focus:bg-white"
                                   />
                               </div>

                               <div className="relative group/input">
                                   <span className="absolute left-3 top-3 text-[10px] font-black uppercase text-indigo-500 tracking-widest bg-white px-1">Akşam</span>
                                   <textarea 
                                     value={day.meals.dinner.content}
                                     onChange={(e) => {
                                        const newPlan = [...dietPlan];
                                        newPlan[idx].meals.dinner.content = e.target.value;
                                        setDietPlan(newPlan);
                                     }}
                                     className="w-full p-4 pt-8 bg-slate-50 border border-slate-100 rounded-2xl text-sm font-medium resize-none h-28 focus:border-indigo-300 outline-none transition-all focus:bg-white"
