                               </div>
                            </div>
                         </div>
                       ))}
                    </div>
                 </div>
              </div>
            )}

            {/* TAB CONTENT: ANALYSIS */}
            {activeTab === 'ANALYSIS' && (
              <div className="flex-1 overflow-y-auto p-12 bg-slate-50">
                 <h3 className="text-3xl font-black italic text-slate-800 mb-8 flex items-center gap-3">
