                                    <Area type="monotone" dataKey="weight" stroke="#10b981" strokeWidth={3} fillOpacity={1} fill="url(#colorWeight)" name="weight" />
                                    <Area type="monotone" dataKey="fatPercentage" stroke="#f59e0b" strokeWidth={3} fill="none" name="fatPercentage" />
