                            </ResponsiveContainer>
                        </div>

                        {/* Son Ölçüm Kartı */}
                        <div className="bg-white p-10 rounded-[3rem] shadow-sm border border-slate-100 grid grid-cols-2 md:grid-cols-4 gap-8">
                            {[
                                { label: 'KİLO', val: selectedCustomer.bodyAnalysis[selectedCustomer.bodyAnalysis.length-1].weight, unit: 'kg', color: 'text-slate-900' },
                                { label: 'YAĞ', val: selectedCustomer.bodyAnalysis[selectedCustomer.bodyAnalysis.length-1].fatPercentage, unit: '%', color: 'text-amber-500' },
                                { label: 'KAS', val: selectedCustomer.bodyAnalysis[selectedCustomer.bodyAnalysis.length-1].muscleMass, unit: 'kg', color: 'text-emerald-500' },
                                { label: 'BMI', val: selectedCustomer.bodyAnalysis[selectedCustomer.bodyAnalysis.length-1].bmi, unit: '', color: 'text-indigo-500' },
                            ].map((stat, i) => (
                                <div key={i} className="text-center">
                                    <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest mb-2">{stat.label}</p>
                                    <p className={`text-5xl font-black italic ${stat.color}`}>{stat.val} <span className="text-sm text-slate-400">{stat.unit}</span></p>
                                </div>
                            ))}
                        </div>

                        {/* Geçmiş Liste */}
                        <div className="bg-white rounded-[3rem] shadow-sm border border-slate-100 overflow-hidden">
                            <table className="w-full text-left">
                                <thead className="bg-slate-50 border-b border-slate-100">
                                    <tr>
                                        <th className="p-6 text-[10px] font-black uppercase text-slate-400 tracking-widest">Tarih</th>
                                        <th className="p-6 text-[10px] font-black uppercase text-slate-400 tracking-widest">Kilo</th>
                                        <th className="p-6 text-[10px] font-black uppercase text-slate-400 tracking-widest">Yağ %</th>
                                        <th className="p-6 text-[10px] font-black uppercase text-slate-400 tracking-widest">Kas</th>
                                        <th className="p-6 text-[10px] font-black uppercase text-slate-400 tracking-widest">BMI</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-50">
                                    {[...selectedCustomer.bodyAnalysis].reverse().map((rec, i) => (
                                        <tr key={i} className="hover:bg-slate-50 transition-colors">
                                            <td className="p-6 font-bold text-slate-700">{new Date(rec.date).toLocaleDateString('tr-TR')}</td>
                                            <td className="p-6 font-black text-slate-900">{rec.weight}</td>
                                            <td className="p-6 font-bold text-slate-600">{rec.fatPercentage}</td>
                                            <td className="p-6 font-bold text-slate-600">{rec.muscleMass}</td>
                                            <td className="p-6 font-bold text-slate-600">{rec.bmi}</td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>
                 )}
              </div>
            )}

            {/* TAB CONTENT: CHAT */}
            {activeTab === 'CHAT' && (
              <div className="flex-1 flex flex-col bg-[#e5ddd5] relative overflow-hidden">
                 {/* Chat Area */}
                 <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/subtle-white-feathers.png')] opacity-50 pointer-events-none"></div>

                 <div className="flex-1 overflow-y-auto p-6 space-y-4 relative z-10 min-h-0" ref={chatScrollRef}>
                    {!selectedCustomer.dietChatHistory || selectedCustomer.dietChatHistory.length === 0 ? (
                       <div className="text-center py-20 text-slate-500 opacity-60 font-bold italic">
                          Henüz mesajlaşma başlamadı.
                       </div>
                    ) : (
                       selectedCustomer.dietChatHistory.map(msg => {
                          const isMe = msg.sender !== 'CUSTOMER';
                          // Manager, Personelin mesajlarını görür ve kimin attığını bilir.
                          const displayName = msg.sender === 'MANAGER' ? 'Yönetici' : (msg.sender === 'DIETITIAN' ? 'Diyetisyen' : selectedCustomer.fullName);

                          return (
                             <div key={msg.id} className={`flex ${isMe ? 'justify-end' : 'justify-start'}`}>
                                <div className={`max-w-[70%] p-4 rounded-2xl shadow-sm relative ${isMe ? 'bg-[#d9fdd3] rounded-tr-none' : 'bg-white rounded-tl-none'}`}>
                                   {isManager && <p className="text-[9px] font-black text-slate-400 mb-1 uppercase tracking-widest">{displayName}</p>}

                                   {msg.type === 'IMAGE' ? (
                                      <img src={msg.content} className="rounded-lg max-w-full h-auto cursor-pointer hover:scale-105 transition-transform" onClick={() => window.open(msg.content, '_blank')} />
                                   ) : msg.type === 'CALL_REQUEST' ? (
                                      <div className="flex items-center gap-3 bg-slate-100 p-3 rounded-xl border border-slate-200">
                                         <Phone size={20} className="text-emerald-500 animate-pulse"/> 
                                         <span className="font-bold text-sm italic">{msg.content}</span>
                                      </div>
                                   ) : (
                                      <p className="text-sm font-medium text-slate-800 leading-relaxed whitespace-pre-wrap">{msg.content}</p>
                                   )}
                                   <span className="text-[9px] text-slate-400 block text-right mt-1 font-bold">
                                      {new Date(msg.timestamp).toLocaleTimeString('tr-TR', {hour:'2-digit', minute:'2-digit'})}
                                   </span>
                                </div>
                             </div>
                          );
                       })
                    )}
                 </div>

                 {/* Input Area */}
                 <div className="p-4 bg-white border-t border-slate-200 relative z-30 flex items-center gap-4 pr-32 shadow-[0_-5px_20px_rgba(0,0,0,0.05)]"> 
                    {/* Added pr-32 to avoid overlap with floating AI button */}
                    <div className="relative">
                        <button onClick={() => setShowCallMenu(!showCallMenu)} className={`p-3 rounded-full transition-all shadow-sm shrink-0 ${showCallMenu ? 'bg-slate-900 text-white' : 'bg-white text-slate-500 hover:bg-emerald-500 hover:text-white'}`} title="İletişim Seçenekleri">
                           {showCallMenu ? <X size={20} /> : <Phone size={20}/>}
                        </button>

                        {/* Call Menu Popover */}
                        {showCallMenu && (
                            <div className="absolute bottom-16 left-0 bg-white border border-slate-200 shadow-2xl rounded-2xl p-2 w-64 animate-in slide-in-from-bottom-4 zoom-in-95 z-[100]">
                                <p className="text-[9px] font-black uppercase text-slate-400 mb-2 px-2 tracking-widest">İletişim Yöntemi</p>
                                <button onClick={() => startCall('AUDIO')} className="w-full flex items-center gap-3 p-3 hover:bg-slate-50 rounded-xl text-left transition-colors">
                                    <div className="bg-emerald-100 text-emerald-600 p-2 rounded-lg"><Phone size={16}/></div>
                                    <span className="text-sm font-bold text-slate-700">Sesli Arama Başlat</span>
                                </button>
                                <button onClick={() => startCall('VIDEO')} className="w-full flex items-center gap-3 p-3 hover:bg-slate-50 rounded-xl text-left transition-colors">
                                    <div className="bg-indigo-100 text-indigo-600 p-2 rounded-lg"><Video size={16}/></div>
                                    <span className="text-sm font-bold text-slate-700">Görüntülü Ara</span>
                                </button>
                                <div className="h-px bg-slate-100 my-1"></div>
                                <div className="p-2 bg-amber-50 rounded-xl border border-amber-100 mt-1">
                                    <p className="text-[9px] font-black uppercase text-amber-600 mb-2 flex items-center gap-1"><Calendar size={10}/> İleri Tarihli Randevu</p>
                                    <div className="flex gap-2">
                                        <input 
                                            type="time" 
                                            value={scheduleTime}
                                            onChange={(e) => setScheduleTime(e.target.value)}
                                            className="w-full bg-white border border-amber-200 rounded-lg px-2 py-1 text-xs font-bold outline-none"
                                        />
                                        <button onClick={sendAppointmentRequest} className="bg-amber-500 text-white rounded-lg px-3 py-1 hover:bg-amber-600"><Send size={12}/></button>
                                    </div>
                                </div>
                            </div>
                        )}
                    </div>

                    <label className="p-3 bg-white text-slate-500 rounded-full hover:bg-emerald-500 hover:text-white transition-all shadow-sm cursor-pointer shrink-0" title="Resim Gönder">
                       <ImageIcon size={20}/>
                       <input type="file" accept="image/*" className="hidden" onChange={handleImageUpload} />
                    </label>
                    <input 
                      value={chatInput}
                      onChange={e => setChatInput(e.target.value)}
                      onKeyDown={e => e.key === 'Enter' && handleSendMessage()}
                      placeholder="Mesaj yazın..." 
                      className="flex-1 p-4 rounded-full border border-slate-300 outline-none focus:border-emerald-500 transition-all font-medium text-slate-700 bg-slate-50" 
                    />
                    <button onClick={handleSendMessage} className="p-4 bg-emerald-500 text-white rounded-full hover:bg-emerald-600 transition-all shadow-lg active:scale-95 shrink-0">
                       <Send size={20} />
                    </button>
                 </div>
              </div>
            )}
          </>
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { useSalon } from '../store/SalonContext';
import { Plus, Trash2, Edit, Scissors, Users, Monitor, X, Check, Key, FileText, ShieldCheck, Coffee, Clock, Banknote, Percent, Zap, Link, Heart, Star, Award, Gift, CreditCard, Package } from 'lucide-react';
import { Service, Staff, Drink, UserRole, LoyaltyRule, MembershipTier, ServicePackage } from '../types';

export const SystemManagement: React.FC = () => {
  const { 
    services, staff, products, devices, updateDevice, addDevice, deleteData, 
    adminKey, receptionistKey, staffKey, updateSystemKeys, kvkkText, updateKvkkText, 
    currentRole, addService, updateService, addStaff, updateStaff,
    drinks, addDrink, updateDrink, loyaltyRate, loyaltyRules, tierLimits, updateLoyaltySettings,
    servicePackages, addPackage, updatePackage
  } = useSalon();

  const [activeTab, setActiveTab] = useState<'SERVICES' | 'STAFF' | 'BAR' | 'LOYALTY' | 'CONTRACT' | 'SECURITY' | 'PACKAGES'>('SERVICES');

  const [showServiceModal, setShowServiceModal] = useState(false);
  const [showStaffModal, setShowStaffModal] = useState(false);
  const [showDrinkModal, setShowDrinkModal] = useState(false);
  const [showLoyaltyModal, setShowLoyaltyModal] = useState(false);
  const [showPackageModal, setShowPackageModal] = useState(false);

  const [editingService, setEditingService] = useState<Service | null>(null);
  const [editingStaff, setEditingStaff] = useState<Staff | null>(null);
  const [editingDrink, setEditingDrink] = useState<Drink | null>(null);
  const [editingLoyalty, setEditingLoyalty] = useState<LoyaltyRule | null>(null);
  const [editingPackage, setEditingPackage] = useState<ServicePackage | null>(null);

  const [securityForm, setSecurityForm] = useState({ admin: adminKey, receptionist: receptionistKey, staff: staffKey });
  const [localKvkk, setLocalKvkk] = useState(kvkkText);
  const [localLoyaltyRate, setLocalLoyaltyRate] = useState(loyaltyRate);
  const [localTierLimits, setLocalTierLimits] = useState(tierLimits);
  const [saved, setSaved] = useState(false);

  const isManager = currentRole === UserRole.MANAGER;

  const handleSecuritySave = (e: React.FormEvent) => {
    e.preventDefault();
    updateSystemKeys(securityForm.admin, securityForm.receptionist, securityForm.staff);
    setSaved(true);
    setTimeout(() => setSaved(false), 3000);
  };

  const handleLoyaltySettingsUpdate = () => {
     updateLoyaltySettings(localLoyaltyRate, loyaltyRules, localTierLimits);
     setSaved(true);
     setTimeout(() => setSaved(false), 2000);
  };

  const handleLoyaltySubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const fd = new FormData(e.target as HTMLFormElement);
    const newRule: LoyaltyRule = {
      id: editingLoyalty?.id || Math.random().toString(36).substr(2, 9),
      minPoints: Number(fd.get('minPoints')),
      reward: fd.get('reward') as string
    };

    let newRules = [...loyaltyRules];
    if (editingLoyalty) {
      newRules = newRules.map(r => r.id === editingLoyalty.id ? newRule : r);
    } else {
      newRules.push(newRule);
    }

    updateLoyaltySettings(localLoyaltyRate, newRules, localTierLimits);
    setShowLoyaltyModal(false);
    setEditingLoyalty(null);
  };

  const handleServiceSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const fd = new FormData(e.target as HTMLFormElement);
    const serviceData: Service = {
      id: editingService?.id || Math.random().toString(36).substr(2, 9),
      name: fd.get('name') as string,
      category: fd.get('category') as any,
      duration: Number(fd.get('duration')),
      price: Number(fd.get('price')),
      commissionRate: Number(fd.get('commissionRate')),
      productCostPerSession: Number(fd.get('productCost')),
      energyAndOverheadPerMinute: Number(fd.get('energyOverhead')) || 5,
      linkedProductId: (fd.get('linkedProductId') as string) || undefined
    };
    editingService ? updateService(serviceData) : addService(serviceData);
    setShowServiceModal(false);
    setEditingService(null);
  };

  const handleStaffSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const fd = new FormData(e.target as HTMLFormElement);
    const staffData: Staff = {
      id: editingStaff?.id || Math.random().toString(36).substr(2, 9),
      name: fd.get('name') as string,
      role: fd.get('role') as string,
      performanceScore: Number(fd.get('performance')) || 100,
      totalSales: editingStaff?.totalSales || 0,
      totalCommissions: editingStaff?.totalCommissions || 0,
      totalPrim: editingStaff?.totalPrim || 0,
      riskScore: 0
    };
    editingStaff ? updateStaff(staffData) : addStaff(staffData);
    setShowStaffModal(false);
    setEditingStaff(null);
  };

  const handleDrinkSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const fd = new FormData(e.target as HTMLFormElement);
    const drinkData: Drink = {
      id: editingDrink?.id || Math.random().toString(36).substr(2, 9),
      name: fd.get('name') as string,
      icon: fd.get('icon') as string,
      description: fd.get('description') as string,
    };
    editingDrink ? updateDrink(drinkData) : addDrink(drinkData);
    setShowDrinkModal(false);
    setEditingDrink(null);
  };

  const handlePackageSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const fd = new FormData(e.target as HTMLFormElement);
    const featuresStr = fd.get('features') as string;
    const pkgData: ServicePackage = {
      id: editingPackage?.id || Math.random().toString(36).substr(2, 9),
      name: fd.get('name') as string,
      description: fd.get('description') as string,
      price: Number(fd.get('price')),
      minTier: fd.get('minTier') as MembershipTier,
      features: featuresStr.split(',').map(f => f.trim()).filter(f => f),
      active: true
    };
    editingPackage ? updatePackage(pkgData) : addPackage(pkgData);
    setShowPackageModal(false);
    setEditingPackage(null);
  };

  if (!isManager) return <div className="py-20 text-center opacity-30 italic font-black text-2xl uppercase tracking-widest">Sadece yönetici yetkisi ile erişilebilir.</div>;

  return (
    <div className="space-y-10 animate-in fade-in duration-500 pb-20">
      <div className="flex flex-wrap bg-white p-3 rounded-[2rem] shadow-sm border border-slate-100 w-fit gap-2 overflow-x-auto no-scrollbar">
        <TabBtn active={activeTab === 'SERVICES'} onClick={() => setActiveTab('SERVICES')} icon={Scissors} label="Hizmetler" />
        <TabBtn active={activeTab === 'STAFF'} onClick={() => setActiveTab('STAFF')} icon={Users} label="Personel" />
        <TabBtn active={activeTab === 'BAR'} onClick={() => setActiveTab('BAR')} icon={Coffee} label="Wellness Bar" />
        <TabBtn active={activeTab === 'PACKAGES'} onClick={() => setActiveTab('PACKAGES')} icon={Package} label="VIP Paketler" />
        <TabBtn active={activeTab === 'LOYALTY'} onClick={() => setActiveTab('LOYALTY')} icon={Award} label="Sadakat & Kart" />
        <TabBtn active={activeTab === 'CONTRACT'} onClick={() => setActiveTab('CONTRACT')} icon={FileText} label="Sözleşme" />
        <TabBtn active={activeTab === 'SECURITY'} onClick={() => setActiveTab('SECURITY')} icon={ShieldCheck} label="Güvenlik" />
      </div>

      <div className="bg-white rounded-[3.5rem] p-10 shadow-xl border border-slate-100 min-h-[600px]">
        {activeTab === 'SERVICES' && (
           <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 animate-in slide-in-from-bottom-5">
              {services.map(s => <ManagementCard key={s.id} title={s.name} sub={s.category} price={`${s.price} TL`} onDelete={() => deleteData(s.id, 'SERVICE')} onEdit={() => { setEditingService(s); setShowServiceModal(true); }} />)}
              <AddCard onClick={() => { setEditingService(null); setShowServiceModal(true); }} label="Yeni Hizmet" icon={Plus} color="rose" />
           </div>
        )}

        {activeTab === 'STAFF' && (
           <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 animate-in slide-in-from-bottom-5">
              {staff.map(s => <ManagementCard key={s.id} title={s.name} sub={s.role} price={`Perf: %${s.performanceScore}`} onDelete={() => deleteData(s.id, 'STAFF')} onEdit={() => { setEditingStaff(s); setShowStaffModal(true); }} />)}
              <AddCard onClick={() => { setEditingStaff(null); setShowStaffModal(true); }} label="Yeni Personel" icon={Plus} color="indigo" />
           </div>
        )}

        {activeTab === 'BAR' && (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 animate-in slide-in-from-bottom-5">
            {drinks.map(d => <ManagementCard key={d.id} title={`${d.icon} ${d.name}`} sub={d.description} onDelete={() => deleteData(d.id, 'DRINK')} onEdit={() => { setEditingDrink(d); setShowDrinkModal(true); }} />)}
            <AddCard onClick={() => { setEditingDrink(null); setShowDrinkModal(true); }} label="Yeni İçecek" icon={Plus} color="amber" />
          </div>
        )}

        {activeTab === 'PACKAGES' && (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 animate-in slide-in-from-bottom-5">
            {servicePackages.map(p => <ManagementCard key={p.id} title={p.name} sub={`${p.minTier}+ Üyeler İçin`} price={`${p.price} TL`} onDelete={() => deleteData(p.id, 'PACKAGE')} onEdit={() => { setEditingPackage(p); setShowPackageModal(true); }} />)}
            <AddCard onClick={() => { setEditingPackage(null); setShowPackageModal(true); }} label="Yeni Paket" icon={Plus} color="indigo" />
          </div>
        )}

        {activeTab === 'LOYALTY' && (
          <div className="space-y-12 animate-in slide-in-from-bottom-5">
             <div className="grid grid-cols-1 xl:grid-cols-2 gap-10">
                 {/* PUAN ORANI */}
                 <div className="bg-slate-50 p-10 rounded-[3rem] border border-slate-200">
                    <h3 className="text-xl font-black italic mb-6">Genel Puan Oranı</h3>
                    <div className="flex items-center gap-6">
