                                       </defs>
                                       <CartesianGrid strokeDasharray="3 3" vertical={false} stroke={tierTheme.subText.includes('slate-400') ? '#e2e8f0' : '#333'} opacity={0.2} />
                                       <XAxis dataKey="date" tickFormatter={(t) => new Date(t).toLocaleDateString('tr-TR', {day:'numeric', month:'short'})} axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 700}} />
                                       <YAxis hide domain={['dataMin - 2', 'dataMax + 2']} />
                                       <RechartsTooltip 
                                           contentStyle={{borderRadius: '1.5rem', border: 'none', padding: '1rem', boxShadow: '0 10px 30px -5px rgba(0,0,0,0.1)', fontWeight: 'bold'}}
                                       />
                                       <Area type="monotone" dataKey="fatPercentage" name="Yağ %" stroke="#f59e0b" strokeWidth={4} fillOpacity={1} fill="url(#colorFat)" />
                                   </AreaChart>
                                </ResponsiveContainer>
                           </div>
                       </div>

                       {/* History Table */}
                       <div className={`${tierTheme.cardBg} border ${tierTheme.border} rounded-[3rem] overflow-hidden shadow-lg`}>
                           <div className="p-8 border-b border-white/10">
                               <h4 className={`text-xl font-black italic ${tierTheme.text}`}>Ölçüm Geçmişi</h4>
                           </div>
                           <table className="w-full text-left">
                                <thead className="bg-black/5">
                                    <tr>
                                        <th className={`p-6 text-[10px] font-black uppercase tracking-widest ${tierTheme.subText}`}>Tarih</th>
                                        <th className={`p-6 text-[10px] font-black uppercase tracking-widest ${tierTheme.subText}`}>Kilo</th>
                                        <th className={`p-6 text-[10px] font-black uppercase tracking-widest ${tierTheme.subText}`}>Yağ %</th>
                                        <th className={`p-6 text-[10px] font-black uppercase tracking-widest ${tierTheme.subText}`}>Kas</th>
                                        <th className={`p-6 text-[10px] font-black uppercase tracking-widest ${tierTheme.subText}`}>BMI</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-white/10">
                                    {[...activeCustomer.bodyAnalysis].reverse().map((rec, i) => (
                                        <tr key={i} className="hover:bg-black/5 transition-colors">
                                            <td className={`p-6 font-bold ${tierTheme.text}`}>{new Date(rec.date).toLocaleDateString('tr-TR')}</td>
                                            <td className={`p-6 font-black ${tierTheme.text}`}>{rec.weight} kg</td>
                                            <td className={`p-6 font-bold text-amber-500`}>%{rec.fatPercentage}</td>
                                            <td className={`p-6 font-bold text-indigo-500`}>{rec.muscleMass} kg</td>
                                            <td className={`p-6 font-bold text-rose-500`}>{rec.bmi}</td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                       </div>
                   </div>
               )}
            </div>
        )}

        {/* ... (Keep PACKAGES, MENU, SCAN, DRINKS, DIET, DOCS tabs) ... */}

      </main>

      {/* ... (Keep Signature Modal and Styles) ... */}
    </div>
  );
};

